// ─────────────────────────────────────────────
// KILLCRITIC 084 - TikTok Assistido DL Nexus V3
// Valida termos proibidos e presença do CTA obrigatório
// ─────────────────────────────────────────────
const payload = $json.body || {};
const texto = JSON.stringify(payload).toLowerCase();

const termos_proibidos = [
  'visita técnica', 'visita tecnica',
  'garantia vitalícia', 'garantia vitalicia',
  'engenheiro diogo', 'preço final', 'preco final',
  'preço fechado', 'preco fechado',
  'canaleta plástica', 'canaleta plastica',
  'hidráulica pura', 'hidraulica pura',
  'preço fechado automático', 'preco fechado automatico'
];

const termos_obrigatorios = [
  'avaliação técnica', 'avaliacao tecnica',
  'tecnólogo', 'tecnologo'
];

const violacoes = termos_proibidos.filter(t => texto.includes(t));
const possui_obrigatorio = termos_obrigatorios.some(t => texto.includes(t));

let status_killcritic = 'APROVADO';
let motivo = 'Nenhuma violação detectada.';

if (violacoes.length > 0) {
  status_killcritic = 'REPROVADO_TERMOS_PROIBIDOS';
  motivo = 'Termos proibidos encontrados: ' + violacoes.join(', ');
}

if (!possui_obrigatorio) {
  status_killcritic = 'REPROVADO_SEM_CTA_OBRIGATORIO';
  motivo = (motivo === 'Nenhuma violação detectada.'
    ? ''
    : motivo + ' | ') + 'CTA obrigatório ausente (avaliação técnica / tecnólogo).';
}

return {
  json: {
    ...payload,
    status_killcritic,
    killcritic_violacoes: violacoes,
    killcritic_motivo: motivo,
    killcritic_timestamp: new Date().toISOString()
  }
};

// ─────────────────────────────────────────────
// Code: Gerar Pacote TikTok - DL Nexus V3
// Gera roteiro, legenda e hashtags para postagem MANUAL
// ─────────────────────────────────────────────
const tema = $json.tema || 'N/A';
const produto = $json.produto || 'N/A';
const legenda = $json.texto || '';

const roteiro = '🎬 ROTEIRO TIKTOK DL SOLUÇÕES\n\n[0-3s] Hook: Mostre o problema do condomínio\n[3-10s] Apresente a solução: ' + produto + '\n[10-25s] Demonstre o resultado da Avaliação Técnica\n[25-30s] CTA: Fale com o Tecnólogo Responsável';

const hashtags = '#DLSolucoes #Condominio #Sindico #AvaliacaoTecnica #EngenhariaCondominal #RiodeJaneiro';

return {
  json: {
    roteiro,
    legenda_sugerida: legenda,
    hashtags,
    tema,
    produto,
    instrucao: 'Grave o vídeo seguindo o roteiro acima e poste manualmente no TikTok com a legenda e hashtags fornecidas.',
    pacote_gerado_em: new Date().toISOString(),
    workflow: '084_PUBLICADOR_TIKTOK_ASSISTIDO',
    status_killcritic: $json.status_killcritic
  }
};
